        await db.query('INSERT INTO seguimiento (fecha_revision, estado_salud, comentarios, foto_url, id_arbol, id_usuario) VALUES (NOW(), ?, ?, ?, ?, ?)', [estado_salud, comentarios, req.file ? req.file.filename : null, id_arbol, id_usuario || 1]);
